        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: PoolQueueMode, into buf: inout [UInt8]) {
        switch value {
        
        
        case .fifo:
            writeInt(&buf, Int32(1))
        
        
        case .lifo:
            writeInt(&buf, Int32(2))
        
        }
    }
}


