/**
 * Error type for the `BreezSdk`
 */
public enum SdkError: Swift.Error {

    
    
    case SparkError(String
    )
    case InsufficientFunds
    case InvalidUuid(String
    )
    /**
     * Invalid input error
     */
    case InvalidInput(String
    )
    /**
     * Network error
     */
    case NetworkError(String
    )
    /**
     * Storage error
     */
    case StorageError(String
    )
    case ChainServiceError(String
    )
    case MaxDepositClaimFeeExceeded(tx: String, vout: UInt32, maxFee: Fee?, requiredFeeSats: UInt64, requiredFeeRateSatPerVbyte: UInt64
    )
    case MissingUtxo(tx: String, vout: UInt32
    )
    case LnurlError(String
    )
    case Signer(String
    )
    /**
     * `optimize_leaves` was called while another optimization run (auto or
     * manual) was already in flight.
     */
    case OptimizationAlreadyRunning
    /**
     * `optimize_leaves` was preempted by the SDK to free leaves for a
     * higher-priority operation (typically a payment).
     */
    case OptimizationCancelled
    case Generic(String
    )
}


